// Verify Cayley-Hamilton Theorem
// p(A) = 0 where p(λ) = det(A - λI)

PROCEDURE VerifyCHT(A)
 BEGIN
 n ← A.rows
 I ← IdentityMatrix(n)

 // Find characteristic polynomial coefficients
 // For 2x2: λ² - tr(A)λ + det(A) = 0
 // General: use Faddeev-LeVerrier algorithm

 trA ← Trace(A)
 detA ← Determinant(A)

 // Characteristic polynomial: λ² - tr(A)λ + det(A)
 // Substitute A: A² - tr(A)A + det(A)I

 A_squared ← MatrixMultiply(A, A)
 term1 ← A_squared
 term2 ← ScalarMultiply(A, trA)
 term3 ← ScalarMultiply(I, detA)

 result ← MatrixSubtract(term1, term2)
 result ← MatrixSubtract(result, term3)

 // If CHT holds, result should be zero matrix
 IF IsZeroMatrix(result) THEN
 RETURN "CHT Verified: p(A) = 0"
 ELSE
 RETURN "CHT Failed"
 END IF
 END PROCEDURE
